export function nextState(current, hook) {
    switch (hook) {
        case "SessionStart":
        case "UserPromptSubmit":
        case "PostToolUse":
            return "running";
        case "Notification":
        case "Stop":
            return "waiting";
        case "SessionEnd":
            return "done";
        case "SubagentStart":
        case "SubagentStop":
        case "PostToolUseFailure":
        case "StopFailure":
            return current;
    }
}
